ON CONFLICT (id) DO UPDATE SET name = EXCLUDED.name, tier = EXCLUDED.tier, country = EXCLUDED.country, tm_competition_url = EXCLUDED.tm_competition_url, is_active = EXCLUDED.is_active;

ON CONFLICT (tm_club_id) DO UPDATE SET league_id = EXCLUDED.league_id, club_name = EXCLUDED.club_name, tm_squad_url = EXCLUDED.tm_squad_url, is_active = true, updated_at = NOW();
